interface EQ {
  stem: string;
  options: string[];
  correctAnswer: number;
  rationale: string;
  learningObjective: string;
  blueprintCategory: string;
  subtopic: string;
  difficulty: number;
  cognitiveLevel: string;
  questionType: "multiple-choice" | "image-interpretation" | "calculation" | "clinical-case";
  scenario?: string;
  exhibitData?: any;
  exam: string;
  regionScope: "US" | "CAN" | "BOTH";
}

export function getBatch56(): EQ[] {
  return [
    { stem: "In tissue Doppler imaging, the a' wave represents:", options: ["Early diastolic annular velocity", "Late diastolic annular velocity during atrial contraction", "Systolic annular velocity", "Isovolumetric contraction velocity"], correctAnswer: 1, rationale: "TDI at the mitral annulus shows three waves: s' (systolic), e' (early diastolic, passive filling), and a' (late diastolic, during atrial contraction). The a' wave velocity reflects atrial mechanical function and annular motion during atrial systole.", learningObjective: "Identify the a' wave on TDI", blueprintCategory: "Hemodynamic Measurements", subtopic: "Diastolic Function Assessment", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The myocardial performance index (Tei index) using the tissue Doppler method is advantageous because:", options: ["It requires two separate Doppler recordings", "It can be obtained from a single cardiac cycle using the TDI waveform at the mitral annulus", "It only measures systolic function", "It requires CW Doppler"], correctAnswer: 1, rationale: "The TDI-based Tei index measures IVCT, IVRT, and ET from a single TDI recording at the mitral annulus in one cardiac cycle, avoiding the beat-to-beat variability inherent in the PW Doppler method (which requires two separate recordings: mitral inflow and LVOT).", learningObjective: "Describe advantage of TDI Tei index", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The Doppler-derived mitral valve pressure gradient uses which equation?", options: ["Continuity equation", "Modified Bernoulli equation: ΔP = 4V² applied to the peak and mean mitral inflow velocities", "Gorlin formula", "Poiseuille equation"], correctAnswer: 1, rationale: "The mean transmitral gradient in MS is obtained by tracing the CW Doppler mitral inflow envelope. The machine applies the modified Bernoulli equation (ΔP = 4V²) to each instantaneous velocity and calculates the mean gradient over the diastolic period.", learningObjective: "Describe method for mitral valve gradient calculation", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A patient with a mechanical mitral valve has a mean gradient of 12 mmHg. This most likely indicates:", options: ["Normal function", "Prosthetic valve obstruction (normal mean gradient for most mechanical mitral valves is <5-6 mmHg)", "Mild dysfunction only", "Normal for this valve type"], correctAnswer: 1, rationale: "Normal mean gradient for mechanical mitral prostheses: generally <5-6 mmHg (varies by type and size). A mean gradient of 12 mmHg is significantly elevated and suggests prosthetic valve obstruction (thrombus, pannus) or patient-prosthesis mismatch. TEE and fluoroscopy are indicated.", learningObjective: "Interpret elevated mechanical MV gradient", blueprintCategory: "Hemodynamic Measurements", subtopic: "Prosthetic Valves", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The echo finding of a 'sparkling' or 'granular' myocardial texture is classically described in:", options: ["Normal myocardium", "Cardiac amyloidosis (though this finding has low sensitivity and specificity)", "Hypertrophic cardiomyopathy", "Dilated cardiomyopathy"], correctAnswer: 1, rationale: "The granular/sparkling myocardial texture was classically described in cardiac amyloidosis. However, this finding has low sensitivity and specificity with modern imaging. More reliable echo findings include: increased wall thickness, biatrial enlargement, small pericardial effusion, and the apical sparing strain pattern.", learningObjective: "Describe sparkling texture in amyloidosis", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal RA area in the A4C view at end-systole is:", options: ["<10 cm²", "<18 cm²", "<25 cm²", "Any size is normal"], correctAnswer: 1, rationale: "Normal RA area: <18 cm² at end-systole (when the atrium is largest, just before tricuspid valve opening). RA area 18-26 cm² = mild dilation, 27-35 cm² = moderate, >35 cm² = severe. RA enlargement is associated with PH, TR, and right heart failure.", learningObjective: "State normal RA area", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "RV wall thickness is normally:", options: ["<3 mm", "<5 mm (measured in subcostal view at end-diastole)", ">8 mm", "Equal to LV wall thickness"], correctAnswer: 1, rationale: "Normal RV free wall thickness: <5 mm at end-diastole (subcostal view). RV hypertrophy (>5 mm) occurs in pulmonary hypertension, pulmonic stenosis, and some cardiomyopathies. The RV wall is much thinner than the LV because it operates in a low-pressure circuit.", learningObjective: "State normal RV wall thickness", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows a patient with dilated LV, reduced EF, and new-onset atrial fibrillation. The E/e' ratio is 18. This indicates:", options: ["Normal filling pressures", "Elevated LV filling pressures, which in the context of AF and reduced EF represents decompensated heart failure", "Only diastolic dysfunction", "Normal for this patient"], correctAnswer: 1, rationale: "E/e' of 18 (>14) indicates elevated filling pressures. Combined with reduced EF, LV dilation, and new AF, this represents decompensated heart failure (HFrEF). In AF, E/e' should be averaged over 5+ beats. LA volume will likely be enlarged, confirming chronic elevation.", learningObjective: "Interpret elevated E/e' in clinical context", blueprintCategory: "Hemodynamic Measurements", subtopic: "Diastolic Function Assessment", difficulty: 3, cognitiveLevel: "analysis", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The echo assessment of tricuspid valve disease should evaluate:", options: ["Only TR severity", "TV morphology, TR mechanism and severity, TV gradient (if stenosis suspected), annular dimensions, RA size, RV function, and PASP", "Only TV morphology", "Only RVSP estimation"], correctAnswer: 1, rationale: "Comprehensive TV assessment: morphology (leaflet thickening, prolapse, retraction, carcinoid changes), TR mechanism (functional vs. organic), TR severity (VC, PISA, jet area, hepatic vein reversal), TS gradient, annular diameter, RA enlargement, RV function (TAPSE, FAC), and PASP estimation.", learningObjective: "List components of TV assessment", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An LVOT VTI of 18 cm with an LVOT diameter of 2.0 cm gives a stroke volume of:", options: ["36.0 mL", "56.5 mL", "72.0 mL", "90.0 mL"], correctAnswer: 1, rationale: "LVOT area = π × (1.0)² = 3.14 cm². SV = 3.14 × 18 = 56.5 mL. This is at the lower end of normal (normal SV approximately 60-100 mL). SVi = 56.5/BSA — if BSA is 1.8 m², SVi = 31.4 mL/m² (<35 = low flow).", learningObjective: "Calculate SV from LVOT measurements", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "application", questionType: "calculation", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The echo finding of 'B-bump' on mitral valve M-mode indicates:", options: ["Normal filling", "Elevated LVEDP, where the late diastolic (atrial contraction) notch on the anterior mitral leaflet M-mode is accentuated", "Mitral stenosis", "Normal atrial contraction"], correctAnswer: 1, rationale: "The B-bump (or B-notch): an accentuated notch on the anterior mitral leaflet M-mode in late diastole, occurring when elevated LVEDP causes premature partial closure of the mitral valve before systole. This is an M-mode sign of elevated LV filling pressures.", learningObjective: "Identify the B-bump on M-mode", blueprintCategory: "Hemodynamic Measurements", subtopic: "Diastolic Function Assessment", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The CSCT exam tests the sonographer's ability to recognize which of the following on a standard TTE?", options: ["Only normal anatomy", "Normal anatomy, common pathology, and normal variants that mimic pathology (Eustachian valve, Chiari network, crista terminalis, moderator band, false tendons)", "Only severe pathology", "Only valve disease"], correctAnswer: 1, rationale: "CSCT candidates must recognize: normal cardiac anatomy, common pathologies (valve disease, cardiomyopathies, pericardial disease), and normal variants that can be confused with pathology (Eustachian valve, Chiari network, crista terminalis, moderator band, LV false tendons, lipomatous hypertrophy of IAS).", learningObjective: "List structures sonographers must recognize", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "Axial resolution in ultrasound is determined primarily by:", options: ["Transducer diameter", "Spatial pulse length (shorter pulses = better axial resolution, achieved with higher frequency and damping)", "Depth of imaging", "Sector width"], correctAnswer: 1, rationale: "Axial resolution = spatial pulse length / 2. Shorter pulses (fewer cycles, more damping, higher frequency) improve axial resolution. Typical axial resolution: 0.5-1.0 mm. Axial resolution is always better than lateral resolution and is the best resolution dimension in ultrasound.", learningObjective: "Describe factors determining axial resolution", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Lateral resolution is determined by:", options: ["Pulse length", "Beam width at the focal point (narrower beam = better lateral resolution)", "Imaging depth only", "Receiver gain"], correctAnswer: 1, rationale: "Lateral resolution equals the beam width. At the focal zone, the beam is narrowest and lateral resolution is best. Focusing (electronic or mechanical) narrows the beam. Lateral resolution varies with depth (worst in the near and far field, best at the focus). It is always worse than axial resolution.", learningObjective: "Describe lateral resolution", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Elevational resolution (slice thickness) in 2D echocardiography is:", options: ["Always the best resolution dimension", "The poorest resolution dimension, determined by the height of the crystal in the elevation plane; it can cause partial volume artifacts", "Equal to axial resolution", "Not relevant to echo imaging"], correctAnswer: 1, rationale: "Elevational (azimuthal/slice thickness) resolution is the poorest dimension — determined by the transducer element height perpendicular to the scan plane. Thick slices include structures outside the intended plane, causing partial volume artifacts (averaging of structures within the slice).", learningObjective: "Describe elevational resolution", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
  ];
}

export function getBatch57(): EQ[] {
  return [
    { stem: "The acoustic impedance of a tissue is:", options: ["Only determined by velocity", "The product of tissue density and sound propagation velocity (Z = ρ × c); differences in impedance at interfaces determine reflection", "Only determined by frequency", "Always constant across tissues"], correctAnswer: 1, rationale: "Acoustic impedance Z = ρ × c (density × velocity). Reflection at interfaces is proportional to the impedance difference between tissues. Large impedance mismatches (soft tissue/air, soft tissue/bone) produce strong reflections, while small mismatches (blood/myocardium) produce weak reflections.", learningObjective: "Define acoustic impedance", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The attenuation coefficient in soft tissue is approximately:", options: ["0.1 dB/cm/MHz", "0.5 dB/cm/MHz", "3.0 dB/cm/MHz", "10 dB/cm/MHz"], correctAnswer: 1, rationale: "Soft tissue attenuation ≈ 0.5 dB/cm/MHz. Total attenuation = 0.5 × depth (cm) × frequency (MHz). For a 3 MHz probe at 15 cm depth: attenuation = 0.5 × 15 × 3 = 22.5 dB (round trip: 45 dB). This determines the need for time-gain compensation (TGC).", learningObjective: "State the soft tissue attenuation coefficient", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Time-gain compensation (TGC) in echo corrects for:", options: ["Frequency-dependent resolution", "Depth-dependent attenuation: deeper structures receive more amplification to compensate for energy loss during sound propagation", "Doppler aliasing", "Color Doppler artifacts"], correctAnswer: 1, rationale: "TGC (also called depth-gain compensation): applies progressively more gain to echoes from deeper structures to compensate for attenuation. Without TGC, deeper structures would appear darker. The sonographer adjusts TGC sliders to achieve uniform brightness throughout the image.", learningObjective: "Explain TGC purpose", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Dynamic range (compression) on the echo machine affects:", options: ["Frame rate only", "The range of echo amplitudes displayed; narrow dynamic range produces high-contrast images, while wide range shows more gray shades and detail", "Doppler sensitivity only", "Transducer frequency"], correctAnswer: 1, rationale: "Dynamic range (log compression): maps the wide range of received echo amplitudes (~100+ dB) to the display range (~30-50 dB). Narrow dynamic range: high contrast, fewer gray levels. Wide dynamic range: lower contrast, more gray levels (subtle tissue differences visible). Typically 50-60 dB for cardiac.", learningObjective: "Describe dynamic range effects", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The piezoelectric effect describes:", options: ["Sound absorption in tissue", "The conversion of electrical energy to mechanical (sound) energy and vice versa by the transducer crystal", "Color Doppler principles", "TGC compensation"], correctAnswer: 1, rationale: "Piezoelectric effect: application of voltage to the crystal causes mechanical deformation (vibration = sound production), and mechanical deformation from returning echoes generates electrical voltage (sound reception). Lead zirconate titanate (PZT) is the most common piezoelectric material in medical transducers.", learningObjective: "Define the piezoelectric effect", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Increasing transducer frequency will:", options: ["Improve penetration", "Improve axial resolution but decrease penetration depth due to increased attenuation", "Increase temporal resolution", "Not affect image quality"], correctAnswer: 1, rationale: "Higher frequency: shorter wavelength → better axial resolution, but greater attenuation per cm → reduced penetration depth. Trade-off: 2 MHz for deep structures in large patients, 3-4 MHz for most adults, 5-8 MHz for pediatric/superficial imaging. Always use the highest frequency that provides adequate depth.", learningObjective: "Describe frequency-resolution-penetration trade-off", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The Eustachian valve is:", options: ["A pathologic structure", "A remnant of the fetal inferior vena cava valve at the IVC-RA junction, which directed oxygenated blood toward the foramen ovale in fetal life", "Always associated with disease", "Found in the LA"], correctAnswer: 1, rationale: "Eustachian valve: embryologic remnant at the IVC-RA junction. In fetal circulation, it directed oxygenated blood from the IVC toward the foramen ovale and into the LA. It is a normal variant seen in 5-10% of echos and should not be mistaken for a mass, vegetation, or thrombus.", learningObjective: "Identify the Eustachian valve", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The coronary sinus drains into the:", options: ["Left atrium", "Right atrium (posterior wall, near the IVC orifice and tricuspid annulus)", "Right ventricle", "Superior vena cava"], correctAnswer: 1, rationale: "The coronary sinus drains most of the coronary venous blood into the posterior RA, near the IVC orifice and the tricuspid annular level. It is protected by the Thebesian valve. It is an important landmark in electrophysiology (CS catheter placement) and can be dilated in certain pathological conditions.", learningObjective: "State the coronary sinus drainage site", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The Thebesian valve guards the orifice of:", options: ["The IVC", "The coronary sinus opening into the RA", "The SVC", "The pulmonary veins"], correctAnswer: 1, rationale: "The Thebesian valve is a thin, semicircular tissue fold at the coronary sinus ostium in the posterior RA. It is variable in size and may be absent. When prominent, it can be mistaken for a mass on echo. It is named after Adam Christian Thebesius (1686-1732).", learningObjective: "Identify the Thebesian valve", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "During echocardiography in a patient with dextrocardia, the sonographer should:", options: ["Use standard transducer positions", "Position the transducer on the right side of the chest (mirror-image of standard positions) and adjust image orientation accordingly", "Only use subcostal views", "Not perform the study"], correctAnswer: 1, rationale: "In dextrocardia (mirror-image), the cardiac apex points to the right. Standard views are obtained from the right parasternal and right apical positions. Image orientation may need to be adjusted. The sonographer should note the situs (situs inversus vs. situs solitus with dextroversion) and any associated anomalies.", learningObjective: "Describe echo approach in dextrocardia", blueprintCategory: "Anatomy/Physiology", subtopic: "Echo Imaging Views", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The Bernoulli equation simplified to ΔP = 4V² assumes:", options: ["Very high proximal velocity", "That the proximal velocity is negligible (<1 m/s), viscous losses are minimal, and flow acceleration effects are small", "No flow present", "Turbulent flow only"], correctAnswer: 1, rationale: "The simplified Bernoulli equation ignores: 1) proximal velocity term (valid when V1 <1 m/s or V2/V1 ratio >3:1), 2) viscous friction term (negligible in most clinical scenarios), and 3) flow acceleration (negligible for steady-state measurements). When V1 >1.5 m/s, use the modified form.", learningObjective: "State simplified Bernoulli assumptions", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A CSCT question: which of the following conditions requires urgent communication to the interpreting physician?", options: ["Mild MR", "Cardiac tamponade with hemodynamic compromise", "Normal EF", "Trace TR"], correctAnswer: 1, rationale: "Critical findings requiring urgent communication: cardiac tamponade, aortic dissection, large pericardial effusion with hemodynamic compromise, severe new valve dysfunction, large mobile mass or thrombus, significant new wall motion abnormality suggesting acute MI, and any finding with immediate clinical implications.", learningObjective: "Identify critical findings for urgent communication", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "The posterior descending artery (PDA) arises from the RCA in approximately:", options: ["50% of the population", "70% of the population", "85% of the population (right-dominant circulation)", "100% of the population"], correctAnswer: 2, rationale: "Coronary dominance: right-dominant (85%) — PDA from RCA. Left-dominant (8-15%) — PDA from LCx. Co-dominant (5-7%) — PDA from both RCA and LCx. The PDA supplies the inferior wall and posterior septum. Dominance determines which coronary territory is responsible for inferior wall motion abnormalities.", learningObjective: "State PDA origin and coronary dominance", blueprintCategory: "Anatomy/Physiology", subtopic: "Coronary Artery Anatomy", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows a quadricuspid aortic valve. This rare anomaly:", options: ["Is always clinically significant", "Usually has four unequal cusps and is associated with aortic regurgitation more commonly than stenosis", "Causes severe AS in all cases", "Is never seen on echo"], correctAnswer: 1, rationale: "Quadricuspid aortic valve: rare (0.01-0.043% prevalence). Most common variant: three equal cusps + one smaller accessory cusp. Aortic regurgitation is the most common functional consequence (from incomplete coaptation). PSAX shows four cusps (X-shaped or Y-shaped closure line).", learningObjective: "Describe quadricuspid aortic valve", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal septal wall thickness at end-diastole in adults is:", options: ["3-5 mm", "6-11 mm", "15-20 mm", "25+ mm"], correctAnswer: 1, rationale: "Normal IVS thickness: 6-11 mm at end-diastole (varies by gender: up to 10 mm women, 11 mm men per ASE). IVS >11 mm (men) or >10 mm (women) indicates hypertrophy. Measured in the PLAX at the MV leaflet tips level at onset of QRS.", learningObjective: "State normal septal wall thickness", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In a CSCT context, the sonographer must verify patient identity before performing the echo by:", options: ["Not required", "Using at least two patient identifiers (name, date of birth, or medical record number) per patient safety protocols", "Only asking the patient's name", "Only checking the requisition"], correctAnswer: 1, rationale: "Patient identification using at least two unique identifiers (name + DOB, name + MRN) is a fundamental patient safety requirement in Canadian healthcare. This prevents wrong-patient studies and ensures accurate medical records. It should be performed before every examination.", learningObjective: "Describe patient identification requirements", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
  ];
}

export function getBatch58(): EQ[] {
  return [
    { stem: "The Doppler frequency shift equation is:", options: ["Δf = 2 × f₀ × V × cos θ / c", "V = Δf × c / (2 × f₀ × cos θ)", "Both A and B are correct — they are rearrangements of the same equation", "None of the above"], correctAnswer: 2, rationale: "The Doppler equation can be expressed as: Δf = 2f₀V cos θ/c (solving for frequency shift) or V = Δfc/(2f₀cos θ) (solving for velocity). Both are rearrangements of the same relationship. The factor of 2 accounts for the round-trip path of the ultrasound beam.", learningObjective: "State the Doppler frequency shift equation", blueprintCategory: "Ultrasound Physics", subtopic: "Doppler Ultrasound", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A bicuspid aortic valve with right-left coronary cusp fusion is the most common pattern, occurring in:", options: ["20% of BAV cases", "50% of BAV cases", "70-80% of BAV cases", "100% of BAV cases"], correctAnswer: 2, rationale: "BAV cusp fusion patterns: right-left coronary cusp fusion (~70-80%, most common), right-noncoronary fusion (~15-20%), left-noncoronary fusion (~5-10%, least common). The fusion pattern may influence the type and rate of aortopathy development and the direction of the AS jet.", learningObjective: "State the most common BAV fusion pattern", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Sinus of Valsalva aneurysm most commonly affects the:", options: ["Non-coronary sinus", "Right coronary sinus (65-85% of cases), and may rupture into the RV or RVOT", "Left coronary sinus", "All sinuses equally"], correctAnswer: 1, rationale: "Sinus of Valsalva aneurysm: right coronary sinus (65-85%), noncoronary sinus (10-30%), left coronary sinus (<5%). Right sinus aneurysms commonly rupture into the RV/RVOT, creating a continuous shunt. Ruptured SVA: continuous flow jet on color Doppler. Associated with VSD in 30-60%.", learningObjective: "Identify the most common sinus of Valsalva aneurysm location", blueprintCategory: "Pathology Recognition", subtopic: "Aortic Disease", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows elevated E/e' with enlarged LA in a patient with preserved EF. This is consistent with:", options: ["Normal hemodynamics", "Heart failure with preserved ejection fraction (HFpEF), where diastolic dysfunction leads to elevated filling pressures despite normal EF", "Only hypertensive heart disease", "Only constrictive pericarditis"], correctAnswer: 1, rationale: "HFpEF: EF ≥50% with clinical heart failure. Echo criteria: elevated E/e' (>14), enlarged LA (>34 mL/m²), elevated TR velocity (>2.8 m/s), and/or elevated LV mass index. Diastolic dysfunction with elevated filling pressures is the hallmark. Additional exercise testing may unmask latent disease.", learningObjective: "Identify HFpEF echo findings", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 3, cognitiveLevel: "analysis", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The Lambl excrescence differs from a vegetation in that Lambl excrescences are:", options: ["Large and mobile", "Very small (typically <1 mm), filamentous, and located on the valve closure lines as degenerative wear-and-tear changes", "Associated with fever", "Located on prosthetic valves only"], correctAnswer: 1, rationale: "Lambl excrescences: tiny (<1 mm), filamentous strands on valve closure lines (coaptation zones), representing degenerative wear-and-tear. They are benign, present in up to 70% of adults at autopsy, and are distinguished from vegetations by their small size, location, and absence of clinical infection.", learningObjective: "Differentiate Lambl excrescences from vegetations", blueprintCategory: "Pathology Recognition", subtopic: "Cardiac Masses", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In diastolic function assessment, the E/A ratio in a 70-year-old with normal diastolic function is typically:", options: [">2.0", "1.5-2.0", "0.8-1.0 (reflecting normal age-related changes in relaxation)", "<0.5"], correctAnswer: 2, rationale: "E/A ratio decreases with age due to normal slowing of active relaxation: age 20-30: ~1.5-2.0, age 40-50: ~1.0-1.5, age 60-70: ~0.8-1.0, age >70: may be <0.8. An E/A <0.8 in an elderly patient may be normal (not necessarily Grade I diastolic dysfunction) if other parameters are normal.", learningObjective: "Interpret age-adjusted E/A ratio", blueprintCategory: "Hemodynamic Measurements", subtopic: "Diastolic Function Assessment", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The mechanical prosthetic valve produces characteristic artifacts on echo that include:", options: ["No artifacts", "Acoustic shadowing, reverberation, and ring-down artifacts from the metallic components", "Only color flow artifacts", "Mirror image artifacts only"], correctAnswer: 1, rationale: "Mechanical valves produce: acoustic shadowing (from metallic components blocking transmission), reverberation (multiple reflections between metallic surfaces), and ring-down/comet-tail artifacts. These obscure structures behind the prosthesis on TTE, often necessitating TEE for complete assessment.", learningObjective: "Identify mechanical valve artifacts", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The Stanford Type B aortic dissection involves:", options: ["The ascending aorta", "The descending aorta only (distal to the left subclavian artery), without ascending aorta involvement", "Both ascending and descending aorta", "The aortic arch exclusively"], correctAnswer: 1, rationale: "Stanford Type B: dissection of the descending aorta (beginning distal to the left subclavian artery origin) without ascending aorta involvement. Type B is generally managed medically unless complicated (malperfusion, rupture, rapid expansion, refractory pain), in which case TEVAR (endovascular repair) is performed.", learningObjective: "Classify Stanford Type B dissection", blueprintCategory: "Pathology Recognition", subtopic: "Aortic Disease", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The true lumen in aortic dissection is identified by:", options: ["Larger size", "Systolic expansion, the lumen connected to the aortic valve, and the side with unobstructed branch vessel origins", "Slower flow", "Spontaneous contrast"], correctAnswer: 1, rationale: "True lumen identification: systolic expansion (pulsatile), connected to the aortic valve, usually smaller in the acute setting, and has faster flow. The false lumen is compressed in systole (may expand in diastole), often larger, may have slower flow/spontaneous echo contrast, and is separated by the intimal flap.", learningObjective: "Identify true vs. false lumen in dissection", blueprintCategory: "Pathology Recognition", subtopic: "Aortic Disease", difficulty: 3, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows Marfan syndrome criteria for aortic root monitoring. The aortic root sinuses dimension at which prophylactic surgery is recommended is:", options: ["35 mm", "40 mm", "≥50 mm (or ≥45 mm with risk factors such as family history of dissection, rapid growth >3 mm/year, or significant AR)", "60 mm"], correctAnswer: 2, rationale: "Marfan aortic root surgery thresholds: ≥50 mm (general), ≥45 mm with risk factors (family history of dissection, growth rate >3 mm/year, desire for pregnancy, significant AR, or BAV with coarctation). Some centers use lower thresholds based on BSA-indexed dimensions.", learningObjective: "State Marfan aortic root surgery threshold", blueprintCategory: "Pathology Recognition", subtopic: "Aortic Disease", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The echo finding of a mobile, serpentine structure in the aortic arch should raise concern for:", options: ["Normal variant", "Aortic atherosclerotic debris or thrombus, which carries significant embolic risk especially if protruding >4 mm, mobile, or ulcerated", "Artifact only", "Lipoma"], correctAnswer: 1, rationale: "Mobile aortic arch atheroma: protruding atherosclerotic plaques in the thoracic aorta are strong risk factors for stroke and peripheral embolism. Complex plaques (>4 mm protrusion, mobile components, ulceration) carry the highest risk. TEE is the primary tool for detecting and grading aortic atheroma.", learningObjective: "Identify mobile aortic atheroma risk", blueprintCategory: "Pathology Recognition", subtopic: "Aortic Disease", difficulty: 3, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In chemotherapy cardiotoxicity monitoring, GLS is preferred over EF because:", options: ["GLS is easier to measure", "GLS detects subclinical myocardial dysfunction before EF decline, allowing earlier protective intervention (>15% relative decrease from baseline is significant)", "GLS is more widely available", "EF is not affected by chemotherapy"], correctAnswer: 1, rationale: "GLS detects subclinical cardiotoxicity 2-3 months before EF decline. A relative decrease of >15% from baseline GLS is considered significant and may prompt cardioprotective therapy (beta-blockers, ACEi/ARBs). GLS has better reproducibility than EF and is recommended by ASE for cancer therapy surveillance.", learningObjective: "Explain GLS advantage in cardiotoxicity monitoring", blueprintCategory: "Hemodynamic Measurements", subtopic: "Advanced Echo Techniques", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In CSCT practice, the sonographer should understand that an echo study interpretation includes:", options: ["Only quantitative data", "Integration of 2D findings, Doppler data, quantitative measurements, clinical context, and comparison with prior studies to reach a comprehensive assessment", "Only qualitative assessment", "Only what the machine calculates automatically"], correctAnswer: 1, rationale: "Echo interpretation integrates: qualitative assessment (wall motion, valve morphology, chamber sizes), quantitative data (measurements, calculations), Doppler findings (velocities, gradients, flow patterns), clinical context (symptoms, history), and comparison with prior studies for serial change assessment.", learningObjective: "Describe comprehensive echo interpretation", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "A patient with LV apical ballooning, mid-segment hypokinesis, and hyperkinetic base following emotional stress most likely has:", options: ["Acute coronary syndrome", "Takotsubo (stress) cardiomyopathy", "Myocarditis", "Pericarditis"], correctAnswer: 1, rationale: "Takotsubo cardiomyopathy: classic pattern of apical and mid-segment akinesis/ballooning with preserved or hyperkinetic basal segments, triggered by emotional or physical stress. EF is acutely reduced but recovers in 1-4 weeks. Coronary angiography shows no obstructive disease.", learningObjective: "Diagnose Takotsubo from echo pattern", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 3, cognitiveLevel: "analysis", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The LVOT VTI in a normal adult is approximately:", options: ["5-10 cm", "18-22 cm", "30-40 cm", "50+ cm"], correctAnswer: 1, rationale: "Normal LVOT VTI: approximately 18-22 cm (range 15-25 cm). Low LVOT VTI (<15 cm) suggests reduced stroke volume/cardiac output. High LVOT VTI (>25 cm) may indicate high-output states (anemia, thyrotoxicosis, AV fistula) or hyperdynamic LV function.", learningObjective: "State normal LVOT VTI range", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
  ];
}

export function getBatch59(): EQ[] {
  return [
    { stem: "A sinus venosus ASD is located:", options: ["In the fossa ovalis region", "At the junction of the SVC (or rarely IVC) and the RA, typically associated with partial anomalous pulmonary venous return", "At the inferior IAS", "In the coronary sinus"], correctAnswer: 1, rationale: "Sinus venosus ASD: located at the SVC-RA junction (superior type, most common) or IVC-RA junction (inferior type, rare). Almost always associated with PAPVR (right upper pulmonary vein draining into the SVC). It is best visualized by TEE or subcostal views, as it is easily missed on standard TTE.", learningObjective: "Locate sinus venosus ASD", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal ascending aortic peak velocity by Doppler is:", options: ["<0.5 m/s", "<1.0 m/s", "1.0-1.7 m/s", ">3.0 m/s"], correctAnswer: 2, rationale: "Normal ascending aortic peak velocity: 1.0-1.7 m/s. Velocities >2.0 m/s in the LVOT or across the AV suggest aortic sclerosis or early stenosis. Peak AV velocity >2.5 m/s indicates mild AS, >3.0 m/s moderate AS, >4.0 m/s severe AS.", learningObjective: "State normal ascending aortic velocity", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The modified Duke criteria for infective endocarditis include echo findings as a major criterion. Positive echo findings include:", options: ["Normal valve appearance", "Mobile vegetation on a valve, abscess, new prosthetic valve dehiscence, or new valvular regurgitation", "Only pericardial effusion", "Only LV dysfunction"], correctAnswer: 1, rationale: "Modified Duke major echo criteria: 1) oscillating intracardiac mass (vegetation) on a valve, on implanted material, or in the regurgitant jet path, 2) abscess/pseudoaneurysm, 3) new prosthetic valve dehiscence, or 4) new valvular regurgitation. Two major or one major + three minor criteria = definite IE.", learningObjective: "State Duke echo criteria for IE", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Prosthetic valve dehiscence on echo appears as:", options: ["Normal sewing ring position", "Rocking motion of the prosthetic valve (>15 degrees), paravalvular space, and significant paravalvular regurgitation", "Only mild regurgitation", "No color Doppler abnormality"], correctAnswer: 1, rationale: "Prosthetic valve dehiscence: excessive rocking motion (>15 degrees) of the valve ring from partial detachment from the annulus, visible paravalvular space, and paravalvular regurgitation. This is a surgical emergency if hemodynamically significant. Most commonly caused by IE or suture breakdown.", learningObjective: "Identify prosthetic valve dehiscence", blueprintCategory: "Pathology Recognition", subtopic: "Prosthetic Valves", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In chronic severe AR, the LV adapts by:", options: ["Concentric hypertrophy", "Eccentric hypertrophy (volume overload causes chamber dilation with proportional wall thickening), maintaining normal wall stress initially", "No adaptation", "Wall thinning only"], correctAnswer: 1, rationale: "Chronic severe AR: volume overload causes eccentric hypertrophy (largest LV among valvular diseases). The LV dilates with proportional increase in wall thickness to normalize wall stress (Laplace). EF is maintained or supranormal initially. Decompensation occurs when the ventricle can no longer compensate.", learningObjective: "Describe LV adaptation in chronic AR", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The echo finding of reversed E/A ratio with Valsalva maneuver in a patient with pseudonormal filling confirms:", options: ["Normal diastolic function", "Grade II diastolic dysfunction, as the Valsalva-induced preload reduction unmasks the underlying impaired relaxation pattern", "Grade III diastolic dysfunction", "Constrictive pericarditis"], correctAnswer: 1, rationale: "In pseudonormal (Grade II) filling, Valsalva reduces preload and LA pressure, unmasking the underlying impaired relaxation: E/A reverses to <1 (E decreases more than A). This maneuver confirms elevated filling pressures. In normal filling, E/A ratio does not reverse with Valsalva.", learningObjective: "Use Valsalva to confirm pseudonormal filling", blueprintCategory: "Hemodynamic Measurements", subtopic: "Diastolic Function Assessment", difficulty: 4, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Chagas disease cardiomyopathy on echo shows:", options: ["Only normal findings", "LV dilation with reduced EF, apical aneurysm (characteristic), regional wall motion abnormalities, and LV thrombus", "Only concentric hypertrophy", "Only pericardial effusion"], correctAnswer: 1, rationale: "Chagas cardiomyopathy (Trypanosoma cruzi): LV dilation with reduced EF (DCM pattern), characteristic apical aneurysm (present in ~50%), inferolateral wall motion abnormalities, and LV thrombus. Conduction disease and ventricular arrhythmias are common. Endemic in Latin America.", learningObjective: "Describe Chagas cardiomyopathy echo findings", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A patient with Noonan syndrome may have which cardiac abnormality?", options: ["BAV only", "Pulmonic valve stenosis (dysplastic valve, most common cardiac defect), HCM, and ASD", "Only coarctation", "Only VSD"], correctAnswer: 1, rationale: "Noonan syndrome cardiac defects: pulmonary valve stenosis (~50%, often dysplastic thickened leaflets resistant to balloon valvuloplasty), HCM (~20-30%), ASD, and less commonly VSD, PDA, and coarctation. Noonan is sometimes called 'male Turner syndrome' but affects both sexes.", learningObjective: "List cardiac defects in Noonan syndrome", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Turner syndrome (45,X) is associated with which cardiac defects?", options: ["Only TR", "Bicuspid aortic valve (~30%), coarctation of the aorta (~10%), and aortic root dilation", "Only PDA", "Only VSD"], correctAnswer: 1, rationale: "Turner syndrome cardiac: BAV (~30%, most common), coarctation (~10%), aortic root dilation (even with trileaflet valve), partial anomalous pulmonary venous return, and elongated transverse arch. Serial aortic root monitoring is recommended due to increased risk of aortic dissection.", learningObjective: "List cardiac defects in Turner syndrome", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Down syndrome (trisomy 21) is most commonly associated with which cardiac defect?", options: ["BAV", "Atrioventricular septal defect (AVSD/endocardial cushion defect)", "Tetralogy of Fallot", "Transposition of great arteries"], correctAnswer: 1, rationale: "Down syndrome cardiac: AVSD (complete AV canal) is the most common (~40% of cardiac defects in Down syndrome), followed by VSD (~30%), ASD, and PDA. Approximately 40-50% of Down syndrome patients have congenital heart disease. AVSD in Down syndrome has better surgical outcome than non-Down AVSD.", learningObjective: "Identify the most common cardiac defect in Down syndrome", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "For the CSCT exam, the role of the cardiac sonographer in patient care includes:", options: ["Only technical image acquisition", "Image acquisition, preliminary interpretation on worksheet, critical finding communication, patient education about the procedure, and professional conduct", "Only final report writing", "Only equipment maintenance"], correctAnswer: 1, rationale: "The CSCT-certified sonographer's role encompasses: patient interaction and procedure explanation, image acquisition using standardized protocols, preliminary worksheet completion with measurements and observations, communication of critical findings, participation in QA/QI, and maintaining professional competency through CPD.", learningObjective: "Describe the sonographer's role in patient care", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "In the 2016 ASE/EACVI algorithm for diastolic function in patients with normal LVEF and no myocardial disease:", options: ["Only E/A ratio is used", "If E/A ≤0.8 and E ≤50 cm/s, Grade I dysfunction is present; if E/A ≥2, Grade III is present; if E/A 0.8-2 (indeterminate), additional parameters decide", "Only e' is needed", "No algorithm exists"], correctAnswer: 1, rationale: "ASE/EACVI 2016 diastolic algorithm for normal EF: Step 1: E/A ≤0.8 with E ≤50 = normal or Grade I (check LA volume, E/e', TR velocity to differentiate). E/A ≥2 = Grade III. E/A 0.8-2 = indeterminate, use 3 of 4 parameters (average E/e' >14, TR velocity >2.8, LA volume >34, E/e' criteria).", learningObjective: "Apply the 2016 diastolic function algorithm", blueprintCategory: "Hemodynamic Measurements", subtopic: "Diastolic Function Assessment", difficulty: 4, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The echo assessment of a patient with chemotherapy-induced cardiotoxicity should include:", options: ["Only EF", "Baseline and serial LVEF, GLS (most sensitive early marker), RV function, valve function, and pericardial assessment at defined intervals per oncology protocols", "Only visual assessment", "Only Doppler measurements"], correctAnswer: 1, rationale: "Chemotherapy cardiotoxicity monitoring: baseline and serial LVEF (biplane Simpson's, ideally 3D), GLS (more sensitive than EF for early detection, >15% relative decrease is significant), diastolic function, RV function, and pericardial assessment. Timing per oncology guidelines.", learningObjective: "Describe cardiotoxicity monitoring protocol", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal aortic root diameter at the sinuses of Valsalva level for a male adult is:", options: ["15-20 mm", "21-36 mm (BSA-dependent)", "40-50 mm", "55+ mm"], correctAnswer: 1, rationale: "Normal sinus of Valsalva diameter: approximately 21-36 mm for males (gender and BSA-dependent). Indexed normal: <21 mm/m². Dilation >37 mm or indexed >21 mm/m² warrants monitoring. In Marfan/BAV, aortic root dilation is the key measurement for surgical decision-making.", learningObjective: "State normal sinus of Valsalva diameter", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
  ];
}

export function getBatch60(): EQ[] {
  return [
    { stem: "An echo shows an LV thrombus. The most common location is:", options: ["Basal septum", "LV apex, especially in the setting of apical akinesis/aneurysm following anterior MI or dilated cardiomyopathy", "Lateral wall", "Inferior wall"], correctAnswer: 1, rationale: "LV thrombus: most commonly apical, associated with apical akinesis/dyskinesis (anterior MI, DCM). The apex has low flow velocity (stasis), creating conditions for thrombus formation (Virchow's triad). Contrast echo improves detection sensitivity vs. standard 2D imaging.", learningObjective: "Identify the most common LV thrombus location", blueprintCategory: "Pathology Recognition", subtopic: "Cardiac Masses", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Endocardial fibroelastosis (EFE) on echo appears as:", options: ["Normal endocardium", "Thick, bright, echogenic endocardium with a DCM pattern (dilated LV, reduced EF), typically in infants and young children", "Only a thickened valve", "Pericardial calcification"], correctAnswer: 1, rationale: "EFE: thickening and fibrosis of the LV endocardium, creating a bright, hyperechoic endocardial surface. Usually presents in infancy with DCM phenotype. Primary EFE is idiopathic; secondary EFE occurs with other congenital defects (HLHS, AS, coarctation). Treatment is supportive; transplant may be needed.", learningObjective: "Describe EFE echo appearance", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo in a patient with hyperthyroidism may show:", options: ["Only bradycardia", "High-output state with increased LV volumes, hyperdynamic systolic function, increased cardiac output, and often atrial fibrillation", "Only pericardial effusion", "Only concentric hypertrophy"], correctAnswer: 1, rationale: "Hyperthyroid cardiac effects: increased CO (high-output state), increased LV volumes, hyperdynamic function (increased EF), reduced SVR, atrial fibrillation, and if prolonged, tachycardia-mediated cardiomyopathy with reduced EF. Mitral valve prolapse may be more common.", learningObjective: "Describe echo findings in hyperthyroidism", blueprintCategory: "Pathology Recognition", subtopic: "Hemodynamics", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A patient with hypothyroidism may show on echo:", options: ["Hyperdynamic LV function", "Pericardial effusion, increased LV wall thickness (from myxedema), mild LV dilation, and diastolic dysfunction", "Only tachycardia", "Normal echo always"], correctAnswer: 1, rationale: "Hypothyroid cardiac effects: pericardial effusion (common, usually small-moderate), increased wall thickness from myxedema, diastolic dysfunction, reduced CO, and possible mild LV dilation. Pericardial effusion resolves with thyroid replacement therapy. Tamponade is rare.", learningObjective: "Describe echo findings in hypothyroidism", blueprintCategory: "Pathology Recognition", subtopic: "Hemodynamics", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The echo assessment of a patient with aortic coarctation should include:", options: ["Only gradient measurement", "Coarctation site visualization, peak and mean gradients, diastolic tail assessment, collateral flow, associated lesions (BAV, VSD), LV function, and aortic arch dimensions", "Only LV function", "Only arch anatomy"], correctAnswer: 1, rationale: "Comprehensive coarctation echo: suprasternal view for site visualization and gradient measurement, diastolic tail (hemodynamic significance), abdominal aorta for diastolic flow pattern, LV function/hypertrophy, associated lesions (BAV in 50-80%, VSD), and complete aortic arch dimensions.", learningObjective: "Describe comprehensive coarctation echo assessment", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In CSCT practice, the echo report should be completed and available within:", options: ["1 month", "24-48 hours for routine studies, immediately for emergent/inpatient studies", "1 week", "No time requirement"], correctAnswer: 1, rationale: "Echo report turnaround: inpatient/emergency studies should be reported immediately or as soon as possible. Outpatient routine studies: within 24-48 hours per most accreditation standards. Critical findings must be communicated immediately regardless of report timing.", learningObjective: "State echo report turnaround requirements", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "The LV mass is calculated using the formula:", options: ["LV mass = EF × EDV", "LV mass = 0.8 × {1.04 × [(LVIDd + IVSd + PWd)³ − LVIDd³]} + 0.6 (ASE-cube formula)", "LV mass = stroke volume × heart rate", "LV mass = LA volume × 2"], correctAnswer: 1, rationale: "ASE-recommended linear method: LV mass = 0.8 × {1.04 × [(LVIDd + IVSd + PWd)³ − LVIDd³]} + 0.6 grams. This is the cube formula corrected for overestimation. It assumes symmetric LV geometry and may be less accurate with asymmetric hypertrophy or remodeling.", learningObjective: "State the LV mass calculation formula", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The Doppler-derived mean PA pressure can be estimated from the peak early PR velocity using:", options: ["mPAP = 4(PR peak velocity)² + RAP", "mPAP = 4 × (peak early PR velocity)² + RAP", "mPAP = TR peak velocity alone", "mPAP = E/e' ratio"], correctAnswer: 1, rationale: "mPAP = 4 × (peak early diastolic PR velocity)² + RAP. This provides the mean PA pressure estimation from the PR jet, complementing the RVSP/PASP estimation from the TR jet. It is useful when TR is insufficient for PASP estimation but PR is measurable.", learningObjective: "Estimate mPAP from PR velocity", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows a patient with cardiac involvement of eosinophilic granulomatosis with polyangiitis (Churg-Strauss). Findings may include:", options: ["Only normal echo", "Eosinophilic myocarditis, endomyocardial fibrosis, mural thrombus, pericardial effusion, and valve thickening", "Only valve disease", "Only pericardial disease"], correctAnswer: 1, rationale: "Eosinophilic cardiac disease: myocarditis (early stage), endomyocardial fibrosis (chronic stage, apical obliteration), mural thrombus (thrombotic stage), pericardial effusion, and valve regurgitation from endomyocardial involvement. Hypereosinophilic syndrome and Churg-Strauss both can cause this pattern.", learningObjective: "Describe eosinophilic cardiac disease echo findings", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 5, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In CSCT practice, the sonographer performing a pediatric echo should understand that:", options: ["Adult normal values apply", "Pediatric echo uses different normal values (Z-scores adjusted for BSA), higher frequency transducers, and requires knowledge of congenital heart disease", "No special considerations exist", "Only adult protocols are used"], correctAnswer: 1, rationale: "Pediatric echo differences: BSA-adjusted Z-scores for normal values, higher frequency transducers (5-12 MHz), subcostal views are often primary windows (no rib interference in small children), knowledge of congenital heart disease anatomy, and different measurement standards.", learningObjective: "Describe pediatric echo considerations", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "The echo evaluation of mechanical dyssynchrony includes:", options: ["Only ECG QRS duration", "Speckle tracking for timing of peak strain in different LV segments, TDI for septal-to-lateral delay, and 3D echo for assessment of mechanical activation patterns", "Only visual assessment", "Only M-mode"], correctAnswer: 1, rationale: "Mechanical dyssynchrony assessment: septal-to-lateral delay by TDI (>65 ms), opposing wall delay (Yu index), speckle tracking radial/longitudinal dyssynchrony, septal flash on 2D, and 3D-derived systolic dyssynchrony index. These are used in CRT candidate selection, though their predictive value is debated.", learningObjective: "Describe echo assessment of mechanical dyssynchrony", blueprintCategory: "Hemodynamic Measurements", subtopic: "Advanced Echo Techniques", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The definition of a 'significant' change in serial EF measurements requires that the difference exceeds:", options: ["1%", "5%", "The measurement variability (typically 8-10% for biplane Simpson's), meaning changes <10% may be within measurement error", "20%"], correctAnswer: 2, rationale: "EF measurement variability: biplane Simpson's has ~8-10% inter-study variability, meaning changes of <8-10% may not represent true change. 3D EF has better reproducibility (~5-6%). GLS has ~4-5% variability. Serial studies should use the same method and ideally the same sonographer/reader.", learningObjective: "Understand EF measurement variability", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A comprehensive CSCT exam preparatory topic includes understanding the hemodynamic effects of ventilation on echo findings because:", options: ["Ventilation has no effect", "Positive pressure ventilation reduces venous return and preload, potentially affecting IVC assessment, chamber sizes, and Doppler velocities compared to spontaneous breathing", "Only negative pressure affects echo", "Only during stress echo"], correctAnswer: 1, rationale: "Positive pressure ventilation (PPV): reduces venous return (dilated IVC even without elevated RAP), may reduce cardiac output, and alters respiratory variation in Doppler signals. The sonographer should note ventilation status and adjust interpretation accordingly (e.g., IVC assessment unreliable during PPV).", learningObjective: "Describe ventilation effects on echo findings", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamics", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
  ];
}
